{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyOGpbKjskn845C1RqtP8XXW"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"T01lGD5RAOO6"},"outputs":[],"source":["import streamlit as st\n","import pandas as pd\n","from sklearn.feature_extraction.text import TfidfVectorizer\n","from sklearn.metrics.pairwise import cosine_similarity\n","\n","# Charger les données\n","@st.cache_data\n","def load_data():\n","    # Charger le fichier CSV des films\n","    return pd.read_csv(\"cinevasion/csv/films_acteurs.csv\")\n","\n","df_films_acteurs = load_data()\n","\n","# Prétraitement des données pour la similarité\n","df_films_acteurs['all_text_clean'] = df_films_acteurs['all_text_clean'].fillna('')\n","\n","# Calcul de TF-IDF\n","@st.cache_resource\n","def calculate_tfidf():\n","    tfidf = TfidfVectorizer()\n","    return tfidf.fit_transform(df_films_acteurs['all_text_clean'])\n","\n","X_tfidf = calculate_tfidf()\n","\n","# Fonction pour recommander des films similaires\n","def recommander_films(titre, df_films_acteurs, X_tfidf, max_reco=5):\n","    try:\n","        # Vérifier si le film existe dans les données\n","        film_index = df_films_acteurs[df_films_acteurs['title'].str.lower() == titre.lower()].index[0]\n","    except IndexError:\n","        return pd.DataFrame(), f\"Aucun film trouvé pour le titre '{titre}'.\"\n","\n","    # Calculer la similarité\n","    cos_sim = cosine_similarity(X_tfidf[film_index], X_tfidf).flatten()\n","    similar_indices = cos_sim.argsort()[::-1][1:max_reco + 1]  # Exclure le film lui-même\n","\n","    # Retourner les films similaires\n","    return df_films_acteurs.iloc[similar_indices], None\n","\n","# Interface utilisateur Streamlit\n","st.title(\"Similarity Page\")\n","st.subheader(\"Trouvez des films similaires à votre film préféré 🎬\")\n","\n","# Barre de recherche pour le titre du film\n","film_title = st.text_input(\"Entrez le titre d'un film :\", placeholder=\"Ex : Titanic\")\n","\n","if st.button(\"Rechercher\") and film_title:\n","    recommandations, erreur = recommander_films(film_title, df_films_acteurs, X_tfidf)\n","\n","    if erreur:\n","        st.warning(erreur)\n","    else:\n","        st.subheader(f\"Films similaires à '{film_title}' :\")\n","        for _, row in recommandations.iterrows():\n","            with st.container():\n","                st.image(row['poster_path'], width=150)\n","                st.write(f\"**{row['title']}** - {row['genres']}\")\n","                st.caption(f\"Note moyenne : {row['averageRating']} | Votes : {row['numVotes']}\")"]}]}